using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLineNumber()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsExchangeCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "555");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExpectedFormat()
    {
        var result = _formatter.FormatPhoneNumber("8005551999");

        Assert.AreEqual("(800) 555-1999", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_Throws(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsExpectedFormat()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.Contains(result, "Johnson");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithMultipleSpaces_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  Leading Spaces  ");

        StringAssert.DoesNotMatch(result, new Regex(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithMultipleSpaces_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("  Trailing Spaces  ");

        StringAssert.DoesNotMatch(result, new Regex(@"-$"));
    }

    [TestMethod]
    public void GenerateSlug_MixedCaseTitle_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("My Blog Post");

        StringAssert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithNumbers_ContainsNumbers()
    {
        var result = _formatter.GenerateSlug("Top 10 Tips");

        StringAssert.Contains(result, "10");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWith2DecimalPlaces()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.Matches(result, new Regex(@"\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoZeros()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(50.00m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_ContainsAmount()
    {
        var result = _formatter.FormatCurrency(50.00m, "€");

        StringAssert.Contains(result, "50.00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-9.50m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

